import numpy as np

def detect_conflicts(memories: list, embeddings: np.ndarray, sim_threshold: float) -> list:
    n = len(memories)
    if n < 2:
        return []
    norms = np.linalg.norm(embeddings, axis=1, keepdims=True)
    E_norm = embeddings / (norms + 1e-8)
    sim = E_norm @ E_norm.T

    conflicts = []
    for i in range(n):
        for j in range(i + 1, n):
            if sim[i, j] >= sim_threshold:
                if memories[i].get('label') != memories[j].get('label'):
                    conflicts.append((i, j, float(sim[i, j])))

    conflicts.sort(key=lambda x: -x[2])
    return conflicts

def resolve_conflicts(memories: list, conflicts: list, strategy: str) -> list:
    if strategy not in ('newer', 'higher_importance'):
        raise ValueError(f"Unknown strategy: {strategy!r}")

    to_remove = set()
    for i, j, _ in conflicts:
        if i in to_remove or j in to_remove:
            continue
        if strategy == 'newer':
            loser = i if memories[i]['timestamp'] <= memories[j]['timestamp'] else j
        else:  # higher_importance
            loser = i if memories[i]['importance'] <= memories[j]['importance'] else j
        to_remove.add(loser)

    return sorted(to_remove)

